body {
  margin: 0;
}

.errors-container {
  height: calc(var(--appsmith-ui-height) * 1px);
  width: calc(var(--appsmith-ui-width) * 1px);
  overflow-y: auto;
  font-family: "Inter", system-ui, sans-serif;
  background: #fff;
  padding: 24px;
  box-sizing: border-box;
  border-radius: var(--appsmith-theme-borderRadius);
  box-shadow: var(--appsmith-theme-boxShadow);
}

/* Top toggle row */
.toggle-row {
  display: flex;
  gap: 16px;
  margin-bottom: 20px;
  font-size: 14px;
}

.toggle {
  cursor: pointer;
  font-weight: 500;
  color: #081a45;
}

.toggle.active {
  font-weight: 600;
  color: #0f1c3f;
}

/* Section header */
.section-title {
  color: #6b6f82;
  font-weight: 600;
  font-size: 14px;
  margin-top: 12px;
  margin-bottom: 8px;
}

/* Group title (e.g., Data Verification I) */
.error-title {
  font-weight: 600;
  font-size: 14px;
  color: #0f1c3f;
  margin: 12px 24px;
}

/* Group container */
.error-group {
  margin-bottom: 12px;
}

/* Error row (checkmark + message + id) */
.error-row {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 8px;
  margin: 12px 0px;
  border-radius: 4px;
  transition: background-color 0.2s ease;
}

.error-row:hover {
  background-color: #eef5ff;
}

.checkmark {
  flex-shrink: 0;
  width: 16px;
  text-align: center;
  margin-top: 3px;
  color: #222;
}

.error-message {
  flex: 1;
  font-size: 13px;
  color: #222;
  line-height: 1.5;
}

.error-id {
  font-size: 12px;
  color: #7b8191;
  white-space: nowrap;
  margin-left: 8px;
}

.no-errors {
  text-align: left;
  color: #6b6f82;
  font-weight: 500;
  font-size: 14px;
  padding: 24px 0;
}

