import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function App() {
  const errors = appsmith.model.data || [];

  // Define stage groupings
   const criticalStages = ["Data Verification I", "Data Verification II", "Integrity Check"];
  const auditStages = ["Data Audit I", "Data Audit II"];

  // Helper to group by stage
  const groupByStage = (items) => {
    return items.reduce((acc, err) => {
      if (!acc[err.error_stage]) acc[err.error_stage] = [];
      acc[err.error_stage].push(err);
      return acc;
    }, {});
  };

  const criticalGrouped = groupByStage(
    errors.filter((e) => criticalStages.includes(e.error_stage))
  );
  const auditGrouped = groupByStage(
    errors.filter((e) => auditStages.includes(e.error_stage))
  );

  const hasCritical = Object.keys(criticalGrouped).length > 0;
  const hasAudit = Object.keys(auditGrouped).length > 0;
  const hasAnyErrors = hasCritical || hasAudit;

  const renderGroupedErrors = (grouped) =>
    Object.entries(grouped).map(([stage, errs]) => (
      <div className="error-group" key={stage}>
        <div className="error-title">{stage}</div>
        {errs.map((error) => (
          <div className="error-row" key={error.validation_check_id}>
            <div className="checkmark">{error.resolved ? "✓" : "•"}</div>
            <div className="error-message">{error.error_message}</div>
            <div className="error-id">{error.validation_check_id}</div>
          </div>
        ))}
      </div>
    ));

  return (
    <div className="errors-container">
      {hasAnyErrors && (
        <div className="toggle-row">
          <span className="toggle">• Unresolved</span>
          <span className="toggle">✓ Resolved</span>
        </div>
      )}

      {!hasAnyErrors && (
        <div className="no-errors">0 Errors</div>
      )}

      {hasCritical && (
        <div className="section">
          <div className="section-title">Critical Errors</div>
          {renderGroupedErrors(criticalGrouped)}
        </div>
      )}

      {hasAudit && (
        <div className="section">
          <div className="section-title">Audit Errors</div>
          {renderGroupedErrors(auditGrouped)}
        </div>
      )}
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
